import React, { useState, useRef, useEffect } from 'react';
import { Form, Button, Row, Col, Banner, Typography, Toast } from '@ies/semi-ui-react';
import Starling from '../../';
import localforage from 'localforage';
import axios from 'axios';
import { without } from 'lodash-es';
const { Option } = Form.Select;
const { Title } = Typography;


export default function Index() {
  const [text, setText] = useState('');
  const form = useRef();
  const pkgVersion = '3.5.2';
  const [locale, setLocale] = useState([]);
  const zoneHost = [
    {
      host: 'https://starling.zijieapi.com',
      label: '国内',
    },
    {
      host: 'https://starling-oversea-useast2a.byteoversea.com',
      label: '海外：GCP',
    },
    {
      host: 'https://starling-oversea.byteoversea.com',
      label: '海外：统一域名',
    },
    {
      host: 'https://starling-sg.byteoversea.com',
      label: '海外：阿里云新加坡',
    },
    {
      host: 'https://starling-va.byteoversea.com',
      label: '海外：阿里云美东',
    },
    {
      host: 'https://starling.tiktokv.us',
      label: '海外：TTP环境',
    },
  ];

  const mode = [
    {
      env: 'normal',
      label: '正式环境'
    },
    {
      env: 'test',
      label: '测试环境'
    },
    {
      env: 'gray',
      label: '灰度环境'
    },
  ]


  const handleSubmit = async value => {
    try {
      const opts = {
        timeout: 5000,
        cdn: 'https://lf3-cdn-tos.draftstatic.com/obj/ies.fe.starling',
        ...value,
      };
      if (value.use_localforage) {
        opts.store = {
          set(key, val) {
            return localforage.setItem(key, val);
          },
          get(key) {
            return localforage.getItem(key);
          },
        };
      }

      const text = await new Starling(opts).load();
      setText(JSON.stringify(text, null, 4));
      Toast.success('加载完成');
    } catch (error) {
      setText(error.toString());
    }
  };

  useEffect(() => {
    form.current.submitForm();
    axios.get(`${require('../../../../conf/getConst')('cliPublicLocaleUrl')}?_r=${Date.now()}`)
      .then(res => {
        const { status, data } = res;
        if (status === 200 && data) {
          const locale = Object.keys(data);
          const topLocale = ['zh', 'zh-CN', 'en', 'en-US'];
          const out = without(locale, ...topLocale)
          out.unshift(...topLocale)
          setLocale(out);
        }
      });
  }, []);

  return (
    <>
      <Banner
        fullMode={false}
        closeIcon={null}
        description={`当前 SDK 版本:  ${pkgVersion}`}
      />
      <br />
      <br />
      <Form
        getFormApi={formApi => (form.current = formApi)}
        onSubmit={handleSubmit}
        labelPosition="top"
        style={{ width: '100%' }}
      >
        <Row gutter={10}>
        <Col span={7}>
          <Title heading={4}>必选项</Title>
            <Form.Input
              field="apiKey"
              label="apiKey"
              initValue="c71af3302f0b11eb813ce152e385e2d5"
            />
            <Form.Select field="zoneHost" label='zoneHost' initValue={zoneHost[0].host} style={{ width: "100%" }}>
              {zoneHost.map(({host, label}) => {
                return <Option value={host}>{host} ({label})</Option>
              })}
            </Form.Select>
            <Form.TagInput
              field="namespace"
              label='namespace'
              initValue={['starling_client']}
              placeholder='回车后提交新增内容'
            />
            <Form.Select field="locale" label='locale' initValue="zh" style={{ width: "100%" }} filter>
              {locale.map((l) => {
                return <Option key={l} value={l}>{l}</Option>
              })}
            </Form.Select>
        </Col>
        <Col span={7}>
          <Title heading={4}>可选项</Title>
            <Form.Select field="mode" label='mode' initValue={mode[0].env} style={{ width: "100%" }}>
              {mode.map(({ env, label }) => {
                return <Option value={env}>{env} ({label})</Option>
              })}
          </Form.Select>
            <Form.TagInput
              field="fallbackLang"
              label='fallbackLang'
              initValue={['zh']}
              placeholder='回车后提交新增内容'
            />
            <Form.Select field="format" label='format' initValue={'merged'} style={{ width: "100%" }}>
            <Option value="merged">merged</Option>
            <Option value="splitted">splitted</Option>
          </Form.Select>
          <Form.Input field='version' label="version（注: 3.4.0+ 支持。若配置则namespace需为空间ID）" initValue="" />
          <Form.Select field="TEAChannelDomain" label='TEAChannelDomain' style={{ width: "100%" }}>
            <Option value="https://mcs.zijieapi.com">国内：https://mcs.zijieapi.com</Option>
            <Option value="">海外不需要配置</Option>
          </Form.Select>
          <Form.Select field="TEAChannel" label='TEAChannel(3.5.2+ 支持)' style={{ width: "100%" }}>
            <Option value="va">va</Option>
            <Option value="sg">sg</Option>
            <Option value="in">in</Option>
          </Form.Select>
          <Form.Select field="TEAChannelType" label='TEAChannelType(3.5.2+ 支持)' style={{ width: "100%" }}>
            <Option value="ttp">ttp</Option>
            <Option value="tcpy">tcpy</Option>
          </Form.Select>
          <Form.Checkbox field="use_localforage" noLabel initValue={false}>
            使用 localforage 存储
          </Form.Checkbox>
        </Col>
        <Col span={10}>
            <Title heading={4}>Response</Title>
          <pre style={{ overflow: 'auto', height: 500 }}>{text}</pre>
        </Col>
      </Row>
        <Button size='large' icon='download' theme='solid' type='primary' block htmlType="submit">load</Button>
      </Form>
    </>
  );
}
